const results = $input.first().json.results || [];

const posts = results.map(page => {
  const props = page.properties;
  const titel = props?.['Titel']?.title?.[0]?.plain_text || 'Ohne Titel';
  const image_prompt = props?.['ImagePrompt']?.rich_text?.[0]?.plain_text || '';
  const saeule = props?.['Säule']?.select?.name || '-';
  const post_typ = props?.['Post-Typ']?.select?.name || '';
  const linkedin_post = props?.['LinkedIn-Post']?.rich_text?.[0]?.plain_text || '';
  const geplantFuer = props?.['Geplant für']?.date?.start || '';

  return {
    json: {
      page_id: page.id,
      titel,
      image_prompt,
      saeule,
      post_typ,
      linkedin_post: linkedin_post.substring(0, 500),
      geplantFuer
    }
  };
});

console.log(`🎨 ${posts.length} Posts mit offenem ImagePrompt gefunden`);
return posts;

const claudeResponse = $input.first().json;
const prevItem = $('Posts einzeln verarbeiten').item.json;

const optimierterPrompt = claudeResponse?.content?.[0]?.text?.trim() || '';

if (!optimierterPrompt) {
  console.log(`⚠️ Kein Prompt erhalten für: ${prevItem.titel}`);
}

console.log(`✅ Prompt optimiert für: ${prevItem.titel}`);
console.log(`   Original: ${prevItem.image_prompt.substring(0, 80)}...`);
console.log(`   Optimiert: ${optimierterPrompt.substring(0, 80)}...`);

return [{
  json: {
    page_id: prevItem.page_id,
    titel: prevItem.titel,
    original_prompt: prevItem.image_prompt,
    optimierter_prompt: optimierterPrompt
  }
}];

const items = $input.all();
console.log(`✅ Image-Prompt-Optimierung abgeschlossen – ${items.length} Post(s) verarbeitet`);
return [{ json: { status: 'Abgeschlossen', verarbeitet: items.length } }];

const items = $input.all();
const heute = new Date().toLocaleDateString('de-DE');

const postListHtml = items.map(i => {
  const titel = i.json?.titel || '-';
  const prompt = i.json?.optimierter_prompt?.substring(0, 150) || '';
  return `<li><strong>${titel}</strong><br><small style="color:#555;font-family:monospace">${prompt}${prompt.length === 150 ? '...' : ''}</small></li>`;
}).join('');

return [{
  json: {
    to: 'wolfgang.baierl@blboardsolutions.de',
    subject: `[LinkedIn] ${items.length} Bildprompt(s) optimiert – bereit für DALL-E 3`,
    body: `<div style="font-family:Arial,sans-serif;max-width:600px">
<h2 style="color:#2c5282">Image-Prompts optimiert</h2>
<p><strong>${items.length}</strong> Bildprompt(s) wurden von Claude für DALL-E 3 optimiert und in der Content Pipeline gespeichert (Feld: <em>Bildprompt Final</em>):</p>
<ul style="line-height:2">${postListHtml}</ul>
<hr style="margin:20px 0">
<p><strong>So nutzt du die Prompts:</strong></p>
<ol>
  <li>Content Pipeline in Notion öffnen</li>
  <li>Beim gewünschten Post das Feld <em>Bildprompt Final</em> kopieren</li>
  <li>In <a href="https://chat.openai.com">ChatGPT → DALL-E 3</a> oder <a href="https://www.bing.com/images/create">Bing Image Creator</a> einfügen</li>
  <li>Generiertes Bild herunterladen und zum Post hochladen</li>
</ol>
<p><a href="https://www.notion.so/35147c762802803f8311ce87bcce27a5" style="background:#2c5282;color:#fff;padding:10px 20px;text-decoration:none;border-radius:4px;display:inline-block">→ Content Pipeline öffnen</a></p>
<p style="color:#999;font-size:0.8em;margin-top:30px">Automatisch generiert am ${heute} · n8n LinkedIn-Workflow</p>
</div>`
  }
}];
